import test from "node:test";
import assert from "node:assert/strict";

import { authorizeRequest } from "../src/authorize-request.mjs";
import { ReportService } from "../src/report-service.mjs";

const policy = {
  allowedRegions: ["us-west"],
  requiredScopes: ["tenant:verified", "audit:enabled"]
};
const route = { anyOfScopes: ["report:read", "report:admin"] };

test("route alternatives do not replace tenant-wide requirements", () => {
  const decision = authorizeRequest(policy, {
    region: "us-west",
    scopes: ["report:read"]
  }, route);
  assert.equal(decision.allowed, false);
});

test("tenant-wide requirements do not replace a route alternative", () => {
  const decision = authorizeRequest(policy, {
    region: "us-west",
    scopes: ["tenant:verified", "audit:enabled"]
  }, route);
  assert.equal(decision.allowed, false);
});

test("all tenant requirements plus either route scope are sufficient", () => {
  for (const routeScope of route.anyOfScopes) {
    const decision = authorizeRequest(policy, {
      region: "us-west",
      scopes: ["tenant:verified", "audit:enabled", routeScope]
    }, route);
    assert.equal(decision.allowed, true);
  }
});

test("service denies a route-only principal even in an allowed region", () => {
  const service = new ReportService({
    defaults: { allowedRegions: ["us-west"], requiredScopes: ["tenant:verified"] },
    overlay: {}
  });
  const response = service.readSummary({
    tenant: "acme",
    region: "us-west",
    scopes: ["report:read"]
  });
  assert.equal(response.status, 403);
});
